"use client"

import { useState } from "react"
import { signIn } from "next-auth/react"
import { useRouter } from "next/navigation"
import Link from "next/link"

export default function Login() {

  const router = useRouter()

  const [email,setEmail] = useState("")
  const [password,setPassword] = useState("")
  const [loading,setLoading] = useState(false)
  const [error,setError] = useState("")

  const handleLogin = async (e) => {
    e.preventDefault()

    setLoading(true)
    setError("")

    const res = await signIn("credentials",{
      email,
      password,
      redirect:false
    })

    setLoading(false)

    if(res?.error){
      setError("Invalid email or password")
    }else{
      router.push("/")
    }
  }

  return(

    <div className="min-h-screen flex items-center justify-center bg-gradient-to-r from-blue-100 via-purple-100 to-pink-100">

      <div className="bg-white shadow-lg rounded-xl p-8 w-full max-w-md">

        <h2 className="text-2xl font-bold text-center text-gray-800 mb-6">
          Login
        </h2>

        <form onSubmit={handleLogin} className="space-y-4">

          <input
            type="email"
            placeholder="Enter email"
            value={email}
            onChange={(e)=>setEmail(e.target.value)}
            className="w-full border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-400"
            required
          />

          <input
            type="password"
            placeholder="Enter password"
            value={password}
            autoComplete="current-password"
            onChange={(e)=>setPassword(e.target.value)}
            className="w-full border rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-indigo-400"
            required
          />

          {error && (
            <p className="text-red-500 text-sm">{error}</p>
          )}

          <button
            type="submit"
            disabled={loading}
            className="w-full bg-indigo-600 text-white py-2 rounded-lg hover:bg-indigo-700 transition"
          >
            {loading ? "Logging in..." : "Login"}
          </button>

        </form>

        <div className="text-center mt-4 text-sm text-gray-600">

          <p>
            Don't have an account?{" "}
            <Link href="/register" className="text-indigo-600 font-semibold">
              Create Account
            </Link>
          </p>

          <p className="mt-2">
            <Link href="/forgot-password" className="text-indigo-600">
              Forgot Password?
            </Link>
          </p>

        </div>

        {/* OAuth Buttons */}

        <div className="mt-6 space-y-2">

          <button
            onClick={()=>signIn("github",{callbackUrl:"/"})}
            className="w-full border py-2 rounded-lg hover:bg-gray-100"
          >
            Login with GitHub
          </button>

          <button
            onClick={()=>signIn("google",{callbackUrl:"/"})}
            className="w-full border py-2 rounded-lg hover:bg-gray-100"
          >
            Login with Google
          </button>

        </div>

      </div>

    </div>
  )
}